import {React , useState} from 'react';
import ReactDOM from 'react-dom';


function Home() {
    const [moviesName] = useState(["Kantara","Ramayana","Rocketry", "Dangal"]); 
    return ( 
        <>
            <h2>Welcome Movie World !</h2>
            <p>This are list of our movie :</p>
            displayMovie();
            function displayMovie(){
                <ol>
            {moviesName.map(moviename => { <li key={moviename}>{moviename}</li>})}
            </ol>
            }
            
        </>
     );
}

export default Home;
